import * as React from 'react';
import { useNavigate } from 'react-router-dom';
// // import PropTypes from 'prop-types';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
// // import CssBaseline from '@mui/material/CssBaseline';
import Divider from '@mui/material/Divider';
import Drawer from '@mui/material/Drawer';
import IconButton from '@mui/material/IconButton';
import List from '@mui/material/List';
// import ListItem from '@mui/material/ListItem';
// import ListItemButton from '@mui/material/ListItemButton';
// import ListItemText from '@mui/material/ListItemText';
// import MenuIcon from '@mui/icons-material/Menu';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
// import { makeStyles } from '@mui/styles';

export default function Header (props) {
	const navigate = useNavigate();
	const { window } = props;
  const [ mobileOpen, setMobileOpen ] = React.useState(false);

  const handleDrawerToggle = () => {
    setMobileOpen((prevState) => !prevState);
  };

  const drawer = (
		// collapsable menu
    <Box onClick={handleDrawerToggle} sx={{ textAlign: 'center' }}>

			{/* logo - Small screen */}
      {/* <Typography variant="h6" sx={{ my: 2, color: '#333' }}>
        MUI
      </Typography> */}

      <Divider />

			{/* Menu items */}
      <List>
				<Button onClick={() => navigate('/')} color='inherit'>Home</Button>
				<Button onClick={() => navigate('/about')} color='inherit'>About</Button>
				<Button onClick={() => navigate('/contact')} color='inherit'>Contact</Button>
        {/* {navItems.map((item) => (
          <ListItem key={item} disablePadding>
            <ListItemButton sx={{ textAlign: 'center' }}>
              <ListItemText primary={item} />
            </ListItemButton>
          </ListItem>
        ))} */}
      </List>

    </Box>
  );

  const container = window !== undefined ? () => window().document.body : undefined;

	return (
		<Box sx={{ flexGrow: 1 }}>
			<AppBar color='inherit' sx={{ boxShadow: '0px 0.3px 15px #e3e3e3' }}>
				<Toolbar sx={{ minHeight: '56px!important' }}>

					{/* logo */}
					<Typography variant="h6" component="div" sx={{ flexGrow: 1, color: '#333' }}>Test</Typography>

					{/* Toggle menu button on mobile screen */}
 					<IconButton
 						aria-label="open drawer"
 						edge="start"
 						onClick={handleDrawerToggle}
 						sx={{ ml: 'auto', display: { sm: 'none' }, color: '#333' }}
 					>
 						<MenuIcon />
 					</IconButton>

					{/* navigation */}
					<Box sx={{ display: { xs: 'none', sm: 'block' } }}>
						<Button onClick={() => navigate('/')} color='inherit'>Home</Button>
						<Button onClick={() => navigate('/about')} color='inherit'>About</Button>
						<Button onClick={() => navigate('/contact')} color='inherit'>Contact</Button>
					</Box>

				</Toolbar>
			</AppBar>

			<nav>
				<Drawer
					container={container}
					variant="temporary"
					open={mobileOpen}
					onClose={handleDrawerToggle}
					anchor="right"
					ModalProps={{
						keepMounted: true, // Better open performance on mobile.
					}}
					sx={{
						display: { xs: 'block', sm: 'none' },
						'& .MuiDrawer-paper': { boxSizing: 'border-box', width: 240 },
					}}
				>
					{drawer}
				</Drawer>
			</nav>

		</Box>
	)
}




